// opReason extracts the "reason" field from an op's JSON payload.
func opReason(payload json.RawMessage) string {
	if len(payload) == 0 {
		return ""
	}
	var m map[string]string
	if err := json.Unmarshal(payload, &m); err != nil {
		return ""
	}
	return m["reason"]
}

// isEvidenceOp returns true if the op is a knowledge evidence operation.
func isEvidenceOp(op string) bool {
	return op == "challenge" || op == "verify" || op == "retract"
}

